import{_ as o,o as c,c as d,as as i}from"./chunks/framework.Dt0DMeWU.js";const m=JSON.parse('{"title":"第四章 VI 和 VIM 编辑器","description":"","frontmatter":{},"headers":[],"relativePath":"backend/Linux/04 第四章 VI和VIM编辑器.md","filePath":"backend/Linux/04 第四章 VI和VIM编辑器.md","lastUpdated":1775485159000}'),a={name:"backend/Linux/04 第四章 VI和VIM编辑器.md"};function t(s,e,n,l,p,r){return c(),d("div",null,[...e[0]||(e[0]=[i('<h1 id="第四章-vi-和-vim-编辑器" tabindex="-1">第四章 <code>VI</code> 和 <code>VIM</code> 编辑器 <a class="header-anchor" href="#第四章-vi-和-vim-编辑器" aria-label="Permalink to &quot;第四章 `VI` 和 `VIM` 编辑器&quot;">​</a></h1><h2 id="学习目标" tabindex="-1">学习目标 <a class="header-anchor" href="#学习目标" aria-label="Permalink to &quot;学习目标&quot;">​</a></h2><p><code>1</code> 了解什么 是 <code>VI</code> 和 <code>VIM</code> 编辑器!</p><p><code>2</code> 熟练 <code>VIM</code> 编辑器一般模式的常见操作</p><p><code>3</code> 熟练 <code>VIM</code> 编辑器编辑模式的的进入和推出方式</p><p><code>4</code> 熟练 <code>VIM</code> 编辑器命令模式的常见命令</p><h2 id="第一节-什么是-vi-和-vim-编辑器" tabindex="-1">第一节 什么是 <code>VI</code> 和 <code>VIM</code> 编辑器 <a class="header-anchor" href="#第一节-什么是-vi-和-vim-编辑器" aria-label="Permalink to &quot;第一节 什么是 `VI` 和 `VIM` 编辑器&quot;">​</a></h2><blockquote><p><code>vi</code> 是 <code>Unix</code> 和类 <code>Unix</code> 操作系统中出现的通用的文本编辑器。<code>vim</code> 是从 <code>vi</code> 发展出来的一个性能更强大的文本编辑器,可以主动的以字体颜色辨别语法的正确性,方便程序设计,<code>vim</code> 和 <code>vi</code> 编辑器完全兼容。使用：<code>vi xxx</code> 文件 或者 <code>vim xxx</code> 文件,简单来说,就是用来编辑文件的一个工具,类似于我们再 <code>Windows</code> 上的一些文本编辑工具,只不过,这里是命令行形式的,不是图形用户界面形式的.接下来我们就准备一个文件,使用 <code>VIM</code> 对文件进行修改</p></blockquote><blockquote><p>复制一个系统的配置文件到 <code>Root</code> 目录下，用以练习 <code>vim</code> 命令</p></blockquote><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[root@192 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]# cp /etc/smartmontools/smartd.conf /root</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[root@192 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]# cd /root/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><img src="https://img.xbin.cn/blog/image-20230703205456739.png" alt=""></p><h2 id="第二节-vim-的一般模式" tabindex="-1">第二节 <code>VIM</code> 的一般模式 <a class="header-anchor" href="#第二节-vim-的一般模式" aria-label="Permalink to &quot;第二节 `VIM` 的一般模式&quot;">​</a></h2><blockquote><p>默认模式,在这个模式中， 你可以使用『上下左右』按键来移动光标，你可以使用『删除字符』或『删除整行』来处理档案内容， 也可以使用『复制、贴上』来处理你的文件数据。</p></blockquote><blockquote><p><code>1</code>.删除和复制操作</p></blockquote><p><img src="https://img.xbin.cn/blog/vim_OjF1J7zRyb.png" alt=""></p><blockquote><p><code>2</code>.光标移动操作 <code>0</code></p></blockquote><p><img src="https://img.xbin.cn/blog/image-20230703211138655.png" alt="image-20230703211138655"></p><h2 id="第三节-vim-的编辑模式" tabindex="-1">第三节 <code>VIM</code> 的编辑模式 <a class="header-anchor" href="#第三节-vim-的编辑模式" aria-label="Permalink to &quot;第三节 `VIM` 的编辑模式&quot;">​</a></h2><blockquote><p>在一般模式中可以进行删除、复制、贴上等等的动作，但是却无法编辑文件内容的！要等到你按下『<code>i</code>, <code>I</code>, <code>o</code>, <code>O</code>, <code>a</code>, <code>A</code>, <code>r</code>, <code>R</code>』等任何一个字母之后才会进入编辑模式。注意了！通常在 <code>Linux</code> 中，按下这些按键时，在画面的左下方会出现『<code>INSERT</code> 或 <code>REPLACE</code> 』的字样，此时才可以进行编辑。而如果要回到一般模式时， 则必须要按下『<code>Esc</code>』这个按键即可退出编辑模式。</p></blockquote><p><img src="https://img.xbin.cn/blog/image-20230703205250698.png" alt="image-20230703205456739"></p><h2 id="第四节-vim-的命令模式" tabindex="-1">第四节 <code>VIM</code> 的命令模式 <a class="header-anchor" href="#第四节-vim-的命令模式" aria-label="Permalink to &quot;第四节 `VIM` 的命令模式&quot;">​</a></h2><blockquote><p>可以进行存盘、退出、显示行号、搜索、批量替换等操作。要在一般模式下输入&quot; / &quot;或 <strong>&quot; : &quot;</strong> 或者&quot;?&quot;可进入命令模式,当命令执行前按 <code>esc</code> 或者命令执行完毕,自动回到一般模式</p></blockquote><p><img src="https://img.xbin.cn/blog/vim1_bdwb6OOJgA.png" alt="image-20230703205250698"></p><ul><li><strong>模式间的切换</strong></li></ul><p><img src="https://img.xbin.cn/blog/vim7_F_WwN43YIy.png" alt="image-20230703205329736"></p><blockquote><p>如果非正常退出,如使用 <code>ctrl</code>+<code>z</code> 退出,再次编辑会提示交换文件&quot;. *.<code>swp</code>&quot;,文件存在,并给出相应的处理方式选项,如果不删除交换文件,每次编辑都会提示,这时可以删除交换文件,通过命令: <code>rm</code> -<code>f</code> .名称即可.<code>swp</code> 即可</p></blockquote><p><img src="https://img.xbin.cn/blog/image-20230703205329736.png" alt=""></p><p><img src="https://img.xbin.cn/blog/vim6_05QzvG_PUU.png" alt=""></p>',28)])])}const b=o(a,[["render",t]]);export{m as __pageData,b as default};
